.notify-btn {
    position: relative;
    background: var(--white);
    border: 1px solid var(--border);
    width: 48px;
    height: 48px;
    border-radius: 50%;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    color: var(--text-muted);
    font-size: 1.2rem;
    transition: all 0.3s ease;
}
.notify-btn:hover { color: var(--primary); border-color: var(--primary); }

.notify-badge {
    position: absolute;
    top: 8px;
    right: 10px;
    min-width: 18px;
    height: 18px;
    background-color: var(--danger-text);
    border-radius: 20px;
    border: 2px solid var(--white);
    font-size: 0.65rem;
    font-weight: 700;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0 3px;
}

/* Notification Dropdown */
.notify-wrapper { position: relative; }
.notify-dropdown {
    display: none; position: absolute; top: calc(100% + 10px); right: 0; width: 360px;
    background: var(--white); border: 1px solid var(--border); border-radius: 16px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.12); z-index: 9999; overflow: hidden; animation: dropIn 0.2s ease;
}
.notify-dropdown.open { display: block; }
@keyframes dropIn { from { opacity: 0; transform: translateY(-8px); } to { opacity: 1; transform: translateY(0); } }
.notify-header { display: flex; align-items: center; justify-content: space-between; padding: 16px 18px 12px; border-bottom: 1px solid var(--border); }
.notify-header h4 { margin: 0; font-size: 0.95rem; font-weight: 700; }
.notify-read-all { font-size: 0.78rem; color: var(--primary); cursor: pointer; border: none; background: none; font-weight: 600; padding: 0; }
.notify-read-all:hover { text-decoration: underline; }
.notify-list { max-height: 380px; overflow-y: auto; }
.notify-item { display: flex; gap: 12px; padding: 13px 18px; border-bottom: 1px solid var(--border); cursor: pointer; transition: background 0.15s; position: relative; text-align: left; }
.notify-item:last-child { border-bottom: none; }
.notify-item:hover { background: var(--secondary); }
.notify-item.unread { background: #f0f9ff; }
.notify-item.unread:hover { background: #e0f2fe; }
.notify-dot { position: absolute; top: 16px; right: 16px; width: 8px; height: 8px; border-radius: 50%; background: var(--primary); }
.notify-icon { width: 38px; height: 38px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 1rem; flex-shrink: 0; }
.notify-icon.blue   { background: #dbeafe; color: #1d4ed8; }
.notify-icon.green  { background: #dcfce7; color: #16a34a; }
.notify-icon.orange { background: #ffedd5; color: #c2410c; }
.notify-icon.purple { background: #ede9fe; color: #7c3aed; }
.notify-icon.red    { background: #fee2e2; color: #dc2626; }
.notify-body { flex: 1; min-width: 0; text-align: left; }
.notify-body p { margin: 0 0 3px 0; font-size: 0.85rem; font-weight: 600; color: var(--text-main); line-height: 1.4; }
.notify-body span { font-size: 0.75rem; color: var(--text-muted); display: block; }
.notify-empty { text-align: center; padding: 36px 20px; color: var(--text-muted); font-size: 0.88rem; }
.notify-footer { padding: 12px 18px; border-top: 1px solid var(--border); text-align: center; }
.notify-footer button { background: none; border: none; color: var(--primary); font-size: 0.83rem; font-weight: 600; cursor: pointer; }

