    // --- Notification System ---
    let notifications = [
        { id: 1, type: 'hw', title: 'ภัทรพล เรียนดี ส่งใบงานที่ 1 แล้ว', desc: 'การบ้าน: ใบงานที่ 1 (รอตรวจประเมิน)', time: '10 นาทีที่แล้ว', unread: true, link: 'grading' },
        { id: 2, type: 'attendance', title: 'แจ้งเตือนการขาดเรียน', desc: 'มีนักเรียนขาดเรียน 2 คน (ม.3/1)', time: '1 ชั่วโมงที่แล้ว', unread: true, link: 'attendance' },
        { id: 3, type: 'system', title: 'ระบบบันทึกคะแนนอัตโนมัติสำเร็จ', desc: 'ดึงข้อมูลคะแนนเข้าฐานข้อมูลเรียบร้อยแล้ว', time: '2 ชั่วโมงที่แล้ว', unread: true, link: 'summary' },
        { id: 4, type: 'game', title: 'อัปเดตสถิติมินิเกม', desc: 'นักเรียนเล่นเกม "ล่าบั๊ก" ผ่านเกณฑ์แล้ว 80%', time: 'เมื่อวานนี้', unread: false, link: 'gamestats' }
    ];

    function toggleNotify() {
        const dropdown = document.getElementById('notify-dropdown');
        dropdown.classList.toggle('open');
        if (dropdown.classList.contains('open')) {
            renderNotifications();
        }
    }

    function renderNotifications() {
        const dropdownList = document.getElementById('notify-list');
        const fullList = document.getElementById('full-notify-list');
        const badge = document.getElementById('notify-badge');

        const unreadCount = notifications.filter(n => n.unread).length;

        if (unreadCount > 0) {
            if(badge) { badge.style.display = 'flex'; badge.innerText = unreadCount; }
        } else {
            if(badge) badge.style.display = 'none';
        }

        if (notifications.length === 0) {
            const emptyHTML = `
                <div class="notify-empty">
                    <i class="fa-regular fa-bell-slash" style="font-size:2rem; margin-bottom:10px; opacity:0.5;"></i>
                    <p style="margin:0;">ไม่มีการแจ้งเตือนใหม่</p>
                </div>`;
            if (dropdownList) dropdownList.innerHTML = emptyHTML;
            if (fullList) fullList.innerHTML = emptyHTML;
            return;
        }

        const itemsHTML = notifications.map(n => {
            let iconClass = '', iconHtml = '';
            if (n.type === 'hw') { iconClass = 'blue'; iconHtml = '<i class="fa-solid fa-file-arrow-up"></i>'; }
            else if (n.type === 'attendance') { iconClass = 'orange'; iconHtml = '<i class="fa-solid fa-triangle-exclamation"></i>'; }
            else if (n.type === 'system') { iconClass = 'green'; iconHtml = '<i class="fa-solid fa-bullhorn"></i>'; }
            else if (n.type === 'game') { iconClass = 'purple'; iconHtml = '<i class="fa-solid fa-gamepad"></i>'; }
            else { iconClass = 'blue'; iconHtml = '<i class="fa-solid fa-bell"></i>'; }

            return `
                <div class="notify-item ${n.unread ? 'unread' : ''}" onclick="clickNotify(${n.id}, '${n.link}')" style="border-radius: 12px; margin-bottom: 4px; border: 1px solid transparent; ${n.unread ? 'border-color: rgba(14, 165, 233, 0.2);' : ''}">
                    <div class="notify-icon ${iconClass}">${iconHtml}</div>
                    <div class="notify-body">
                        <p>${n.title}</p>
                        <span>${n.desc}</span>
                        <div style="font-size:0.7rem; color:var(--text-muted); margin-top:4px;">${n.time}</div>
                    </div>
                    ${n.unread ? '<div class="notify-dot"></div>' : ''}
                </div>
            `;
        }).join('');

        if (dropdownList) dropdownList.innerHTML = itemsHTML;
        if (fullList) fullList.innerHTML = itemsHTML;
    }

    function markAllRead() {
        notifications.forEach(n => n.unread = false);
        renderNotifications();
    }

    function clickNotify(id, linkId) {
        const notif = notifications.find(n => n.id === id);
        if (notif) notif.unread = false;

        toggleNotify(); // close dropdown
        if (linkId) switchTab(linkId);
        renderNotifications(); // update badge
    }

    // Close dropdown when clicking outside
    document.addEventListener('click', function(event) {
        const wrapper = document.getElementById('notify-wrapper');
        const dropdown = document.getElementById('notify-dropdown');
        if (wrapper && !wrapper.contains(event.target) && dropdown) {
            dropdown.classList.remove('open');
        }
    });

    // Initial render on load
    window.addEventListener('load', () => {
        renderNotifications();
    });
</script>
